/**
 * Organization Repository
 *
 * Data access layer for Organization entities.
 * Since Organization IS the tenant root, this uses a non-tenant repository pattern.
 *
 * @module modules/_core/organization/organization.repository
 *
 * @example
 * ```typescript
 * import { OrganizationRepository } from '@/modules/_core/organization/organization.repository';
 *
 * const repo = container.resolve('OrganizationRepository');
 * const org = await repo.findBySlug('my-restaurant');
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { PrismaClient, OrganizationStatus, Prisma } from '@prisma/client';

import { TOKENS } from '@/core/kernel/container';
import { AppException } from '@/core/exceptions/app.exception';
import { notDeleted, softDelete } from '@/config/database';

import type {
  Organization,
  OrganizationWithRelations,
  OrganizationListParams,
  OrganizationSummary,
} from '@/modules/_core/organization/organization.types';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

/**
 * Paginated result type
 */
export interface PaginatedResult<T> {
  /** Array of entities */
  data: T[];
  /** Pagination metadata */
  meta: {
    page: number;
    perPage: number;
    total: number;
    totalPages: number;
  };
}

/**
 * Create organization data (input for repository)
 */
export interface CreateOrganizationData {
  name: string;
  slug: string;
  email: string;
  phone?: string | null;
  logo?: string | null;
  settings?: Prisma.JsonValue;
  status?: OrganizationStatus;
  planId?: string | null;
  trialEndsAt?: Date | null;
}

/**
 * Update organization data (input for repository)
 */
export interface UpdateOrganizationData {
  name?: string;
  slug?: string;
  email?: string;
  phone?: string | null;
  logo?: string | null;
  settings?: Prisma.JsonValue;
  status?: OrganizationStatus;
  planId?: string | null;
  trialEndsAt?: Date | null;
}

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

const DEFAULT_PER_PAGE = 20;
const MAX_PER_PAGE = 100;

// -----------------------------------------------------------------------------
// Organization Repository
// -----------------------------------------------------------------------------

/**
 * Repository for Organization entity operations.
 *
 * Handles all database operations for organizations including:
 * - CRUD operations
 * - Slug lookups
 * - Status filtering
 * - Pagination and search
 *
 * @remarks
 * This is a non-tenant repository since Organization IS the tenant root.
 * Soft delete is enforced on all operations.
 *
 * @example
 * ```typescript
 * @injectable()
 * class OrganizationService {
 *   constructor(
 *     @inject('OrganizationRepository') private repo: OrganizationRepository
 *   ) {}
 *
 *   async getBySlug(slug: string) {
 *     return this.repo.findBySlug(slug);
 *   }
 * }
 * ```
 */
@injectable()
export class OrganizationRepository {
  constructor(
    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
  ) {}

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Finds all organizations with pagination and filtering
   *
   * @param params - Query parameters (pagination, sorting, filtering)
   * @returns Paginated list of organizations
   *
   * @example
   * ```typescript
   * const result = await repo.findAll({
   *   page: 1,
   *   perPage: 10,
   *   status: 'ACTIVE',
   *   sortBy: 'createdAt',
   * });
   * ```
   */
  async findAll(params: OrganizationListParams = {}): Promise<PaginatedResult<Organization>> {
    const {
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      status,
      planId,
      search,
      createdAfter,
      createdBefore,
      includeDeleted = false,
      sortBy = 'createdAt',
      sortOrder = 'desc',
    } = params;

    // Normalize pagination
    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    // Build where clause
    const where: Prisma.OrganizationWhereInput = {
      ...(includeDeleted ? {} : notDeleted),
      ...(status && { status }),
      ...(planId && { planId }),
      ...(search && {
        OR: [
          { name: { contains: search, mode: 'insensitive' } },
          { email: { contains: search, mode: 'insensitive' } },
          { slug: { contains: search, mode: 'insensitive' } },
        ],
      }),
      ...(createdAfter && { createdAt: { gte: createdAfter } }),
      ...(createdBefore && { createdAt: { lte: createdBefore } }),
    };

    // Build orderBy
    const orderBy: Prisma.OrganizationOrderByWithRelationInput = {
      [sortBy]: sortOrder,
    };

    // Execute count and find in parallel
    const [total, data] = await Promise.all([
      this.prisma.organization.count({ where }),
      this.prisma.organization.findMany({
        where,
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data: data as Organization[],
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds all organizations as summaries (for dropdowns, etc.)
   *
   * @param params - Optional filtering params
   * @returns Array of organization summaries
   */
  async findAllSummaries(params: Partial<OrganizationListParams> = {}): Promise<OrganizationSummary[]> {
    const { status, includeDeleted = false } = params;

    const where: Prisma.OrganizationWhereInput = {
      ...(includeDeleted ? {} : notDeleted),
      ...(status && { status }),
    };

    const organizations = await this.prisma.organization.findMany({
      where,
      select: {
        id: true,
        name: true,
        slug: true,
        logo: true,
        status: true,
        createdAt: true,
        plan: {
          select: {
            name: true,
          },
        },
        _count: {
          select: {
            users: true,
          },
        },
      },
      orderBy: { name: 'asc' },
    });

    return organizations.map((org) => ({
      id: org.id,
      name: org.name,
      slug: org.slug,
      logo: org.logo,
      status: org.status,
      planName: org.plan?.name,
      userCount: org._count.users,
      createdAt: org.createdAt,
    }));
  }

  /**
   * Finds an organization by ID
   *
   * @param id - Organization ID
   * @returns Organization or null
   */
  async findById(id: string): Promise<Organization | null> {
    const result = await this.prisma.organization.findFirst({
      where: { id, ...notDeleted },
    });

    return result as Organization | null;
  }

  /**
   * Finds an organization by ID with relations
   *
   * @param id - Organization ID
   * @returns Organization with relations or null
   */
  async findByIdWithRelations(id: string): Promise<OrganizationWithRelations | null> {
    const result = await this.prisma.organization.findFirst({
      where: { id, ...notDeleted },
      include: {
        plan: {
          select: {
            id: true,
            name: true,
            tier: true,
          },
        },
        _count: {
          select: {
            users: true,
            menus: true,
            orders: true,
          },
        },
      },
    });

    return result as OrganizationWithRelations | null;
  }

  /**
   * Finds an organization by ID or throws
   *
   * @param id - Organization ID
   * @returns Organization
   * @throws {AppException} If not found
   */
  async findByIdOrThrow(id: string): Promise<Organization> {
    const organization = await this.findById(id);

    if (!organization) {
      throw AppException.notFound('Organization', id);
    }

    return organization;
  }

  /**
   * Finds an organization by slug
   *
   * @param slug - Organization slug
   * @returns Organization or null
   */
  async findBySlug(slug: string): Promise<Organization | null> {
    const result = await this.prisma.organization.findFirst({
      where: { slug, ...notDeleted },
    });

    return result as Organization | null;
  }

  /**
   * Finds an organization by slug or throws
   *
   * @param slug - Organization slug
   * @returns Organization
   * @throws {AppException} If not found
   */
  async findBySlugOrThrow(slug: string): Promise<Organization> {
    const organization = await this.findBySlug(slug);

    if (!organization) {
      throw AppException.notFound('Organization', slug);
    }

    return organization;
  }

  /**
   * Finds an organization by email
   *
   * @param email - Organization email
   * @returns Organization or null
   */
  async findByEmail(email: string): Promise<Organization | null> {
    const result = await this.prisma.organization.findFirst({
      where: { email: email.toLowerCase(), ...notDeleted },
    });

    return result as Organization | null;
  }

  /**
   * Checks if a slug exists
   *
   * @param slug - Slug to check
   * @param excludeId - Optional ID to exclude from check
   * @returns True if slug exists
   */
  async slugExists(slug: string, excludeId?: string): Promise<boolean> {
    const count = await this.prisma.organization.count({
      where: {
        slug,
        ...notDeleted,
        ...(excludeId && { id: { not: excludeId } }),
      },
    });

    return count > 0;
  }

  /**
   * Checks if an email exists
   *
   * @param email - Email to check
   * @param excludeId - Optional ID to exclude from check
   * @returns True if email exists
   */
  async emailExists(email: string, excludeId?: string): Promise<boolean> {
    const count = await this.prisma.organization.count({
      where: {
        email: email.toLowerCase(),
        ...notDeleted,
        ...(excludeId && { id: { not: excludeId } }),
      },
    });

    return count > 0;
  }

  /**
   * Counts organizations by status
   *
   * @param status - Optional status to filter
   * @returns Count
   */
  async count(status?: OrganizationStatus): Promise<number> {
    return this.prisma.organization.count({
      where: {
        ...notDeleted,
        ...(status && { status }),
      },
    });
  }

  // ---------------------------------------------------------------------------
  // Write Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new organization
   *
   * @param data - Create data
   * @returns Created organization
   */
  async create(data: CreateOrganizationData): Promise<Organization> {
    const result = await this.prisma.organization.create({
      data: {
        name: data.name,
        slug: data.slug,
        email: data.email.toLowerCase(),
        phone: data.phone || null,
        logo: data.logo || null,
        settings: data.settings || {},
        status: data.status || OrganizationStatus.ACTIVE,
        planId: data.planId || null,
        trialEndsAt: data.trialEndsAt || null,
      },
    });

    return result as Organization;
  }

  /**
   * Updates an organization
   *
   * @param id - Organization ID
   * @param data - Update data
   * @returns Updated organization
   * @throws {AppException} If not found
   */
  async update(id: string, data: UpdateOrganizationData): Promise<Organization> {
    // Verify exists
    await this.findByIdOrThrow(id);

    const result = await this.prisma.organization.update({
      where: { id },
      data: {
        ...(data.name !== undefined && { name: data.name }),
        ...(data.slug !== undefined && { slug: data.slug }),
        ...(data.email !== undefined && { email: data.email.toLowerCase() }),
        ...(data.phone !== undefined && { phone: data.phone }),
        ...(data.logo !== undefined && { logo: data.logo }),
        ...(data.settings !== undefined && { settings: data.settings }),
        ...(data.status !== undefined && { status: data.status }),
        ...(data.planId !== undefined && { planId: data.planId }),
        ...(data.trialEndsAt !== undefined && { trialEndsAt: data.trialEndsAt }),
      },
    });

    return result as Organization;
  }

  /**
   * Updates organization settings (merge)
   *
   * @param id - Organization ID
   * @param settings - Settings to merge
   * @returns Updated organization
   */
  async updateSettings(id: string, settings: Prisma.JsonValue): Promise<Organization> {
    const organization = await this.findByIdOrThrow(id);

    // Merge settings
    const currentSettings = (organization.settings as Record<string, unknown>) || {};
    const newSettings = settings as Record<string, unknown>;
    const mergedSettings = this.deepMerge(currentSettings, newSettings);

    const result = await this.prisma.organization.update({
      where: { id },
      data: { settings: mergedSettings },
    });

    return result as Organization;
  }

  /**
   * Updates organization status
   *
   * @param id - Organization ID
   * @param status - New status
   * @returns Updated organization
   */
  async updateStatus(id: string, status: OrganizationStatus): Promise<Organization> {
    await this.findByIdOrThrow(id);

    const result = await this.prisma.organization.update({
      where: { id },
      data: { status },
    });

    return result as Organization;
  }

  // ---------------------------------------------------------------------------
  // Delete Operations
  // ---------------------------------------------------------------------------

  /**
   * Soft deletes an organization
   *
   * @param id - Organization ID
   * @returns Deleted organization
   * @throws {AppException} If not found
   */
  async softDelete(id: string): Promise<Organization> {
    await this.findByIdOrThrow(id);

    const result = await this.prisma.organization.update({
      where: { id },
      data: softDelete(),
    });

    return result as Organization;
  }

  /**
   * Restores a soft-deleted organization
   *
   * @param id - Organization ID
   * @returns Restored organization
   */
  async restore(id: string): Promise<Organization> {
    // Find including deleted
    const organization = await this.prisma.organization.findFirst({
      where: { id },
    });

    if (!organization) {
      throw AppException.notFound('Organization', id);
    }

    const result = await this.prisma.organization.update({
      where: { id },
      data: { deletedAt: null },
    });

    return result as Organization;
  }

  // ---------------------------------------------------------------------------
  // Helper Methods
  // ---------------------------------------------------------------------------

  /**
   * Deep merges two objects
   */
  private deepMerge(target: Record<string, unknown>, source: Record<string, unknown>): Record<string, unknown> {
    const result = { ...target };

    for (const [key, value] of Object.entries(source)) {
      if (value !== undefined && value !== null) {
        if (typeof value === 'object' && !Array.isArray(value)) {
          result[key] = this.deepMerge(
            (result[key] as Record<string, unknown>) || {},
            value as Record<string, unknown>
          );
        } else {
          result[key] = value;
        }
      }
    }

    return result;
  }
}
